7	/// Permission level assigned to a tool invocation or runtime session.
8	#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
9	pub enum PermissionMode {
10	    ReadOnly,
11	    WorkspaceWrite,
12	    DangerFullAccess,
13	    Prompt,
14	    Allow,
15	}
16	
17	impl PermissionMode {
18	    #[must_use]
19	    pub fn as_str(self) -> &'static str {
20	        match self {
21	            Self::ReadOnly => "read-only",
22	            Self::WorkspaceWrite => "workspace-write",
23	            Self::DangerFullAccess => "danger-full-access",
24	            Self::Prompt => "prompt",
25	            Self::Allow => "allow",
26	        }
27	    }
28	}
