30	/// Hook-provided override applied before standard permission evaluation.
31	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
32	pub enum PermissionOverride {
33	    Allow,
34	    Deny,
35	    Ask,
36	}
37	
38	/// Additional permission context supplied by hooks or higher-level orchestration.
39	#[derive(Debug, Clone, PartialEq, Eq, Default)]
40	pub struct PermissionContext {
41	    override_decision: Option<PermissionOverride>,
42	    override_reason: Option<String>,
43	}
44	
45	impl PermissionContext {
46	    #[must_use]
47	    pub fn new(
48	        override_decision: Option<PermissionOverride>,
49	        override_reason: Option<String>,
50	    ) -> Self {
51	        Self {
52	            override_decision,
53	            override_reason,
54	        }
55	    }
56	
57	    #[must_use]
58	    pub fn override_decision(&self) -> Option<PermissionOverride> {
59	        self.override_decision
60	    }
61	
62	    #[must_use]
63	    pub fn override_reason(&self) -> Option<&str> {
64	        self.override_reason.as_deref()
65	    }
66	}
