68	/// Full authorization request presented to a permission prompt.
69	#[derive(Debug, Clone, PartialEq, Eq)]
70	pub struct PermissionRequest {
71	    pub tool_name: String,
72	    pub input: String,
73	    pub current_mode: PermissionMode,
74	    pub required_mode: PermissionMode,
75	    pub reason: Option<String>,
76	}
77	
78	/// User-facing decision returned by a [`PermissionPrompter`].
79	#[derive(Debug, Clone, PartialEq, Eq)]
80	pub enum PermissionPromptDecision {
81	    Allow,
82	    Deny { reason: String },
83	}
84	
85	/// Prompting interface used when policy requires interactive approval.
86	pub trait PermissionPrompter {
87	    fn decide(&mut self, request: &PermissionRequest) -> PermissionPromptDecision;
88	}
89	
90	/// Final authorization result after evaluating static rules and prompts.
91	#[derive(Debug, Clone, PartialEq, Eq)]
92	pub enum PermissionOutcome {
93	    Allow,
94	    Deny { reason: String },
95	}
96	
97	/// Evaluates permission mode requirements plus allow/deny/ask rules.
98	#[derive(Debug, Clone, PartialEq, Eq)]
99	pub struct PermissionPolicy {
100	    active_mode: PermissionMode,
101	    tool_requirements: BTreeMap<String, PermissionMode>,
102	    allow_rules: Vec<PermissionRule>,
103	    deny_rules: Vec<PermissionRule>,
104	    ask_rules: Vec<PermissionRule>,
105	}
106	
107	impl PermissionPolicy {
108	    #[must_use]
109	    pub fn new(active_mode: PermissionMode) -> Self {
110	        Self {
111	            active_mode,
112	            tool_requirements: BTreeMap::new(),
113	            allow_rules: Vec::new(),
114	            deny_rules: Vec::new(),
115	            ask_rules: Vec::new(),
116	        }
117	    }
118	
119	    #[must_use]
120	    pub fn with_tool_requirement(
121	        mut self,
122	        tool_name: impl Into<String>,
123	        required_mode: PermissionMode,
124	    ) -> Self {
125	        self.tool_requirements
126	            .insert(tool_name.into(), required_mode);
127	        self
128	    }
129	
130	    #[must_use]
131	    pub fn with_permission_rules(mut self, config: &RuntimePermissionRuleConfig) -> Self {
132	        self.allow_rules = config
133	            .allow()
134	            .iter()
135	            .map(|rule| PermissionRule::parse(rule))
136	            .collect();
137	        self.deny_rules = config
138	            .deny()
139	            .iter()
140	            .map(|rule| PermissionRule::parse(rule))
141	            .collect();
142	        self.ask_rules = config
143	            .ask()
144	            .iter()
145	            .map(|rule| PermissionRule::parse(rule))
146	            .collect();
147	        self
148	    }
149	
150	    #[must_use]
151	    pub fn active_mode(&self) -> PermissionMode {
152	        self.active_mode
153	    }
154	
155	    #[must_use]
156	    pub fn required_mode_for(&self, tool_name: &str) -> PermissionMode {
157	        self.tool_requirements
158	            .get(tool_name)
159	            .copied()
160	            .unwrap_or(PermissionMode::DangerFullAccess)
161	    }
162	
163	    #[must_use]
164	    pub fn authorize(
165	        &self,
166	        tool_name: &str,
167	        input: &str,
168	        prompter: Option<&mut dyn PermissionPrompter>,
169	    ) -> PermissionOutcome {
170	        self.authorize_with_context(tool_name, input, &PermissionContext::default(), prompter)
171	    }
172	
173	    #[must_use]
174	    #[allow(clippy::too_many_lines)]
175	    pub fn authorize_with_context(
176	        &self,
177	        tool_name: &str,
178	        input: &str,
179	        context: &PermissionContext,
180	        prompter: Option<&mut dyn PermissionPrompter>,
181	    ) -> PermissionOutcome {
182	        if let Some(rule) = Self::find_matching_rule(&self.deny_rules, tool_name, input) {
183	            return PermissionOutcome::Deny {
184	                reason: format!(
185	                    "Permission to use {tool_name} has been denied by rule '{}'",
186	                    rule.raw
187	                ),
188	            };
189	        }
190	
191	        let current_mode = self.active_mode();
192	        let required_mode = self.required_mode_for(tool_name);
193	        let ask_rule = Self::find_matching_rule(&self.ask_rules, tool_name, input);
194	        let allow_rule = Self::find_matching_rule(&self.allow_rules, tool_name, input);
195	
196	        match context.override_decision() {
197	            Some(PermissionOverride::Deny) => {
198	                return PermissionOutcome::Deny {
199	                    reason: context.override_reason().map_or_else(
200	                        || format!("tool '{tool_name}' denied by hook"),
201	                        ToOwned::to_owned,
202	                    ),
203	                };
204	            }
205	            Some(PermissionOverride::Ask) => {
206	                let reason = context.override_reason().map_or_else(
207	                    || format!("tool '{tool_name}' requires approval due to hook guidance"),
208	                    ToOwned::to_owned,
209	                );
210	                return Self::prompt_or_deny(
211	                    tool_name,
212	                    input,
213	                    current_mode,
214	                    required_mode,
215	                    Some(reason),
216	                    prompter,
217	                );
218	            }
219	            Some(PermissionOverride::Allow) => {
220	                if let Some(rule) = ask_rule {
221	                    let reason = format!(
222	                        "tool '{tool_name}' requires approval due to ask rule '{}'",
223	                        rule.raw
224	                    );
225	                    return Self::prompt_or_deny(
226	                        tool_name,
227	                        input,
228	                        current_mode,
229	                        required_mode,
230	                        Some(reason),
231	                        prompter,
232	                    );
233	                }
234	                if allow_rule.is_some()
235	                    || current_mode == PermissionMode::Allow
236	                    || current_mode >= required_mode
237	                {
238	                    return PermissionOutcome::Allow;
239	                }
240	            }
241	            None => {}
242	        }
243	
244	        if let Some(rule) = ask_rule {
245	            let reason = format!(
246	                "tool '{tool_name}' requires approval due to ask rule '{}'",
247	                rule.raw
248	            );
249	            return Self::prompt_or_deny(
250	                tool_name,
251	                input,
252	                current_mode,
253	                required_mode,
254	                Some(reason),
255	                prompter,
256	            );
257	        }
258	
259	        if allow_rule.is_some()
260	            || current_mode == PermissionMode::Allow
261	            || current_mode >= required_mode
262	        {
263	            return PermissionOutcome::Allow;
264	        }
265	
266	        if current_mode == PermissionMode::Prompt
267	            || (current_mode == PermissionMode::WorkspaceWrite
268	                && required_mode == PermissionMode::DangerFullAccess)
269	        {
270	            let reason = Some(format!(
271	                "tool '{tool_name}' requires approval to escalate from {} to {}",
272	                current_mode.as_str(),
273	                required_mode.as_str()
274	            ));
275	            return Self::prompt_or_deny(
276	                tool_name,
277	                input,
278	                current_mode,
279	                required_mode,
280	                reason,
281	                prompter,
282	            );
283	        }
284	
285	        PermissionOutcome::Deny {
286	            reason: format!(
287	                "tool '{tool_name}' requires {} permission; current mode is {}",
288	                required_mode.as_str(),
289	                current_mode.as_str()
290	            ),
291	        }
292	    }
293	
294	    fn prompt_or_deny(
295	        tool_name: &str,
296	        input: &str,
297	        current_mode: PermissionMode,
298	        required_mode: PermissionMode,
299	        reason: Option<String>,
300	        mut prompter: Option<&mut dyn PermissionPrompter>,
301	    ) -> PermissionOutcome {
302	        let request = PermissionRequest {
303	            tool_name: tool_name.to_string(),
304	            input: input.to_string(),
305	            current_mode,
306	            required_mode,
307	            reason: reason.clone(),
308	        };
309	
310	        match prompter.as_mut() {
311	            Some(prompter) => match prompter.decide(&request) {
312	                PermissionPromptDecision::Allow => PermissionOutcome::Allow,
313	                PermissionPromptDecision::Deny { reason } => PermissionOutcome::Deny { reason },
314	            },
315	            None => PermissionOutcome::Deny {
316	                reason: reason.unwrap_or_else(|| {
317	                    format!(
318	                        "tool '{tool_name}' requires approval to run while mode is {}",
319	                        current_mode.as_str()
320	                    )
321	                }),
322	            },
323	        }
324	    }
325	
326	    fn find_matching_rule<'a>(
327	        rules: &'a [PermissionRule],
328	        tool_name: &str,
329	        input: &str,
330	    ) -> Option<&'a PermissionRule> {
331	        rules.iter().find(|rule| rule.matches(tool_name, input))
332	    }
333	}
334	
335	#[derive(Debug, Clone, PartialEq, Eq)]
336	struct PermissionRule {
337	    raw: String,
338	    tool_name: String,
339	    matcher: PermissionRuleMatcher,
340	}
341	
342	#[derive(Debug, Clone, PartialEq, Eq)]
343	enum PermissionRuleMatcher {
344	    Any,
345	    Exact(String),
346	    Prefix(String),
347	}
348	
349	impl PermissionRule {
350	    fn parse(raw: &str) -> Self {
351	        let trimmed = raw.trim();
352	        let open = find_first_unescaped(trimmed, '(');
353	        let close = find_last_unescaped(trimmed, ')');
354	
355	        if let (Some(open), Some(close)) = (open, close) {
356	            if close == trimmed.len() - 1 && open < close {
357	                let tool_name = trimmed[..open].trim();
358	                let content = &trimmed[open + 1..close];
359	                if !tool_name.is_empty() {
360	                    let matcher = parse_rule_matcher(content);
361	                    return Self {
362	                        raw: trimmed.to_string(),
363	                        tool_name: tool_name.to_string(),
364	                        matcher,
365	                    };
366	                }
367	            }
368	        }
369	
370	        Self {
371	            raw: trimmed.to_string(),
372	            tool_name: trimmed.to_string(),
373	            matcher: PermissionRuleMatcher::Any,
374	        }
375	    }
376	
377	    fn matches(&self, tool_name: &str, input: &str) -> bool {
378	        if self.tool_name != tool_name {
379	            return false;
380	        }
381	
382	        match &self.matcher {
383	            PermissionRuleMatcher::Any => true,
384	            PermissionRuleMatcher::Exact(expected) => {
385	                extract_permission_subject(input).is_some_and(|candidate| candidate == *expected)
386	            }
387	            PermissionRuleMatcher::Prefix(prefix) => extract_permission_subject(input)
388	                .is_some_and(|candidate| candidate.starts_with(prefix)),
389	        }
390	    }
391	}
392	
393	fn parse_rule_matcher(content: &str) -> PermissionRuleMatcher {
394	    let unescaped = unescape_rule_content(content.trim());
395	    if unescaped.is_empty() || unescaped == "*" {
396	        PermissionRuleMatcher::Any
397	    } else if let Some(prefix) = unescaped.strip_suffix(":*") {
398	        PermissionRuleMatcher::Prefix(prefix.to_string())
399	    } else {
400	        PermissionRuleMatcher::Exact(unescaped)
401	    }
402	}
403	
404	fn unescape_rule_content(content: &str) -> String {
405	    content
406	        .replace(r"\(", "(")
407	        .replace(r"\)", ")")
408	        .replace(r"\\", r"\")
409	}
410	
411	fn find_first_unescaped(value: &str, needle: char) -> Option<usize> {
412	    let mut escaped = false;
413	    for (idx, ch) in value.char_indices() {
414	        if ch == '\\' {
415	            escaped = !escaped;
416	            continue;
417	        }
418	        if ch == needle && !escaped {
419	            return Some(idx);
420	        }
421	        escaped = false;
422	    }
423	    None
424	}
425	
426	fn find_last_unescaped(value: &str, needle: char) -> Option<usize> {
427	    let chars = value.char_indices().collect::<Vec<_>>();
428	    for (pos, (idx, ch)) in chars.iter().enumerate().rev() {
429	        if *ch != needle {
430	            continue;
431	        }
432	        let mut backslashes = 0;
433	        for (_, prev) in chars[..pos].iter().rev() {
434	            if *prev == '\\' {
435	                backslashes += 1;
436	            } else {
437	                break;
438	            }
439	        }
440	        if backslashes % 2 == 0 {
441	            return Some(*idx);
442	        }
443	    }
444	    None
445	}
446	
447	fn extract_permission_subject(input: &str) -> Option<String> {
448	    let parsed = serde_json::from_str::<Value>(input).ok();
449	    if let Some(Value::Object(object)) = parsed {
450	        for key in [
451	            "command",
452	            "path",
453	            "file_path",
454	            "filePath",
455	            "notebook_path",
456	            "notebookPath",
457	            "url",
458	            "pattern",
459	            "code",
460	            "message",
461	        ] {
462	            if let Some(value) = object.get(key).and_then(Value::as_str) {
463	                return Some(value.to_string());
464	            }
465	        }
466	    }
467	
468	    (!input.trim().is_empty()).then(|| input.to_string())
469	}
