479	    struct RecordingPrompter {
480	        seen: Vec<PermissionRequest>,
481	        allow: bool,
482	    }
483	
484	    impl PermissionPrompter for RecordingPrompter {
485	        fn decide(&mut self, request: &PermissionRequest) -> PermissionPromptDecision {
486	            self.seen.push(request.clone());
487	            if self.allow {
488	                PermissionPromptDecision::Allow
489	            } else {
490	                PermissionPromptDecision::Deny {
491	                    reason: "not now".to_string(),
492	                }
493	            }
494	        }
495	    }
