497	    #[test]
498	    fn allows_tools_when_active_mode_meets_requirement() {
499	        let policy = PermissionPolicy::new(PermissionMode::WorkspaceWrite)
500	            .with_tool_requirement("read_file", PermissionMode::ReadOnly)
501	            .with_tool_requirement("write_file", PermissionMode::WorkspaceWrite);
502	
503	        assert_eq!(
504	            policy.authorize("read_file", "{}", None),
505	            PermissionOutcome::Allow
506	        );
507	        assert_eq!(
508	            policy.authorize("write_file", "{}", None),
509	            PermissionOutcome::Allow
510	        );
511	    }
