513	    #[test]
514	    fn denies_read_only_escalations_without_prompt() {
515	        let policy = PermissionPolicy::new(PermissionMode::ReadOnly)
516	            .with_tool_requirement("write_file", PermissionMode::WorkspaceWrite)
517	            .with_tool_requirement("bash", PermissionMode::DangerFullAccess);
518	
519	        assert!(matches!(
520	            policy.authorize("write_file", "{}", None),
521	            PermissionOutcome::Deny { reason } if reason.contains("requires workspace-write permission")
522	        ));
523	        assert!(matches!(
524	            policy.authorize("bash", "{}", None),
525	            PermissionOutcome::Deny { reason } if reason.contains("requires danger-full-access permission")
526	        ));
