645	    fn hook_deny_short_circuits_permission_flow() {
646	        let policy = PermissionPolicy::new(PermissionMode::DangerFullAccess)
647	            .with_tool_requirement("bash", PermissionMode::DangerFullAccess);
648	        let context = PermissionContext::new(
649	            Some(PermissionOverride::Deny),
650	            Some("blocked by hook".to_string()),
