661	    #[test]
662	    fn hook_ask_forces_prompt() {
663	        let policy = PermissionPolicy::new(PermissionMode::DangerFullAccess)
664	            .with_tool_requirement("bash", PermissionMode::DangerFullAccess);
665	        let context = PermissionContext::new(
666	            Some(PermissionOverride::Ask),
667	            Some("hook requested confirmation".to_string()),
