1	//! Permission enforcement layer that gates tool execution based on the
2	//! active `PermissionPolicy`.
3	
4	use crate::permissions::{PermissionMode, PermissionOutcome, PermissionPolicy};
5	use serde::{Deserialize, Serialize};
6	
7	#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
8	#[serde(tag = "outcome")]
9	pub enum EnforcementResult {
10	    /// Tool execution is allowed.
11	    Allowed,
12	    /// Tool execution was denied due to insufficient permissions.
13	    Denied {
14	        tool: String,
15	        active_mode: String,
16	        required_mode: String,
17	        reason: String,
18	    },
19	}
20	
21	#[derive(Debug, Clone, PartialEq)]
22	pub struct PermissionEnforcer {
23	    policy: PermissionPolicy,
24	}
25	
26	impl PermissionEnforcer {
27	    #[must_use]
28	    pub fn new(policy: PermissionPolicy) -> Self {
29	        Self { policy }
30	    }
31	
32	    /// Check whether a tool can be executed under the current permission policy.
33	    /// Auto-denies when prompting is required but no prompter is provided.
34	    pub fn check(&self, tool_name: &str, input: &str) -> EnforcementResult {
35	        // When the active mode is Prompt, defer to the caller's interactive
36	        // prompt flow rather than hard-denying (the enforcer has no prompter).
37	        if self.policy.active_mode() == PermissionMode::Prompt {
38	            return EnforcementResult::Allowed;
39	        }
40	
41	        let outcome = self.policy.authorize(tool_name, input, None);
42	
43	        match outcome {
44	            PermissionOutcome::Allow => EnforcementResult::Allowed,
45	            PermissionOutcome::Deny { reason } => {
46	                let active_mode = self.policy.active_mode();
47	                let required_mode = self.policy.required_mode_for(tool_name);
48	                EnforcementResult::Denied {
49	                    tool: tool_name.to_owned(),
50	                    active_mode: active_mode.as_str().to_owned(),
51	                    required_mode: required_mode.as_str().to_owned(),
52	                    reason,
53	                }
54	            }
55	        }
56	    }
57	
58	    #[must_use]
59	    pub fn is_allowed(&self, tool_name: &str, input: &str) -> bool {
60	        matches!(self.check(tool_name, input), EnforcementResult::Allowed)
61	    }
62	
63	    #[must_use]
64	    pub fn active_mode(&self) -> PermissionMode {
65	        self.policy.active_mode()
66	    }
67	
68	    /// Classify a file operation against workspace boundaries.
69	    pub fn check_file_write(&self, path: &str, workspace_root: &str) -> EnforcementResult {
70	        let mode = self.policy.active_mode();
71	
72	        match mode {
73	            PermissionMode::ReadOnly => EnforcementResult::Denied {
74	                tool: "write_file".to_owned(),
75	                active_mode: mode.as_str().to_owned(),
76	                required_mode: PermissionMode::WorkspaceWrite.as_str().to_owned(),
77	                reason: format!("file writes are not allowed in '{}' mode", mode.as_str()),
78	            },
79	            PermissionMode::WorkspaceWrite => {
80	                if is_within_workspace(path, workspace_root) {
81	                    EnforcementResult::Allowed
82	                } else {
83	                    EnforcementResult::Denied {
84	                        tool: "write_file".to_owned(),
85	                        active_mode: mode.as_str().to_owned(),
86	                        required_mode: PermissionMode::DangerFullAccess.as_str().to_owned(),
87	                        reason: format!(
88	                            "path '{}' is outside workspace root '{}'",
89	                            path, workspace_root
90	                        ),
91	                    }
92	                }
93	            }
94	            // Allow and DangerFullAccess permit all writes
95	            PermissionMode::Allow | PermissionMode::DangerFullAccess => EnforcementResult::Allowed,
96	            PermissionMode::Prompt => EnforcementResult::Denied {
97	                tool: "write_file".to_owned(),
98	                active_mode: mode.as_str().to_owned(),
99	                required_mode: PermissionMode::WorkspaceWrite.as_str().to_owned(),
100	                reason: "file write requires confirmation in prompt mode".to_owned(),
101	            },
102	        }
103	    }
104	
105	    /// Check if a bash command should be allowed based on current mode.
106	    pub fn check_bash(&self, command: &str) -> EnforcementResult {
107	        let mode = self.policy.active_mode();
108	
109	        match mode {
110	            PermissionMode::ReadOnly => {
111	                if is_read_only_command(command) {
112	                    EnforcementResult::Allowed
113	                } else {
114	                    EnforcementResult::Denied {
115	                        tool: "bash".to_owned(),
116	                        active_mode: mode.as_str().to_owned(),
117	                        required_mode: PermissionMode::WorkspaceWrite.as_str().to_owned(),
118	                        reason: format!(
119	                            "command may modify state; not allowed in '{}' mode",
120	                            mode.as_str()
121	                        ),
122	                    }
123	                }
124	            }
125	            PermissionMode::Prompt => EnforcementResult::Denied {
126	                tool: "bash".to_owned(),
127	                active_mode: mode.as_str().to_owned(),
128	                required_mode: PermissionMode::DangerFullAccess.as_str().to_owned(),
129	                reason: "bash requires confirmation in prompt mode".to_owned(),
130	            },
131	            // WorkspaceWrite, Allow, DangerFullAccess: permit bash
132	            _ => EnforcementResult::Allowed,
133	        }
134	    }
135	}
136	
137	/// Simple workspace boundary check via string prefix.
138	fn is_within_workspace(path: &str, workspace_root: &str) -> bool {
139	    let normalized = if path.starts_with('/') {
140	        path.to_owned()
141	    } else {
142	        format!("{workspace_root}/{path}")
143	    };
144	
145	    let root = if workspace_root.ends_with('/') {
146	        workspace_root.to_owned()
147	    } else {
148	        format!("{workspace_root}/")
149	    };
150	
151	    normalized.starts_with(&root) || normalized == workspace_root.trim_end_matches('/')
152	}
153	
154	/// Conservative heuristic: is this bash command read-only?
155	fn is_read_only_command(command: &str) -> bool {
156	    let first_token = command
157	        .split_whitespace()
158	        .next()
159	        .unwrap_or("")
160	        .rsplit('/')
161	        .next()
162	        .unwrap_or("");
163	
164	    matches!(
165	        first_token,
166	        "cat"
167	            | "head"
168	            | "tail"
169	            | "less"
170	            | "more"
171	            | "wc"
172	            | "ls"
173	            | "find"
174	            | "grep"
175	            | "rg"
176	            | "awk"
177	            | "sed"
178	            | "echo"
179	            | "printf"
180	            | "which"
181	            | "where"
182	            | "whoami"
183	            | "pwd"
184	            | "env"
185	            | "printenv"
186	            | "date"
187	            | "cal"
188	            | "df"
189	            | "du"
190	            | "free"
191	            | "uptime"
192	            | "uname"
193	            | "file"
194	            | "stat"
195	            | "diff"
196	            | "sort"
197	            | "uniq"
198	            | "tr"
199	            | "cut"
200	            | "paste"
201	            | "tee"
202	            | "xargs"
203	            | "test"
204	            | "true"
205	            | "false"
206	            | "type"
207	            | "readlink"
208	            | "realpath"
209	            | "basename"
210	            | "dirname"
211	            | "sha256sum"
212	            | "md5sum"
213	            | "b3sum"
214	            | "xxd"
215	            | "hexdump"
216	            | "od"
217	            | "strings"
218	            | "tree"
219	            | "jq"
220	            | "yq"
221	            | "python3"
222	            | "python"
223	            | "node"
224	            | "ruby"
225	            | "cargo"
226	            | "rustc"
227	            | "git"
228	            | "gh"
229	    ) && !command.contains("-i ")
230	        && !command.contains("--in-place")
231	        && !command.contains(" > ")
232	        && !command.contains(" >> ")
233	}
